create table if not exists sources(id uuid primary key default gen_random_uuid(),name text not null,url text not null unique,type text not null,created_at timestamptz default now());
create table if not exists threats(id text primary key,title text not null,category text not null,severity text not null,summary text not null,impact text,publication_date date not null,confidence text not null default 'medium',affected_products text[] default '{}',immediate_actions text[] default '{}',created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists cves(id text primary key,threat_id text references threats(id) on delete set null,vendor text,product text,cvss numeric,kev boolean default false,published_at timestamptz,updated_at timestamptz,source_id uuid references sources(id));
create table if not exists iocs(id uuid primary key default gen_random_uuid(),threat_id text references threats(id) on delete cascade,ioc_type text not null,ioc_value text not null,verification_status text not null check (verification_status in ('Verified','Reported','Unconfirmed')),source_id uuid references sources(id),unique(threat_id,ioc_type,ioc_value));
create table if not exists mitre_mappings(id uuid primary key default gen_random_uuid(),threat_id text references threats(id) on delete cascade,tactic text not null,technique text not null,sub_technique text,explanation text);
create table if not exists watchlists(id uuid primary key default gen_random_uuid(),user_id uuid,item_type text not null,item_value text not null,created_at timestamptz default now(),unique(user_id,item_type,item_value));
create table if not exists analyst_notes(id uuid primary key default gen_random_uuid(),threat_id text references threats(id),content_md text not null,generated_by text not null default 'rule_based',confidence text default 'medium',created_at timestamptz default now());
